# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
from datetime import datetime

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = 'your-project-id'
PUBSUB_TOPIC = f'projects/{PROJECT_ID}/topics/file-processing-topic'

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    Processes files, writes metadata to Firestore, and publishes to Pub/Sub.
    
    Service Account Permissions Required:
    - roles/storage.admin (Storage Admin)
    - roles/datastore.user (Datastore User)
    - roles/pubsub.publisher (Pub/Sub Publisher)
    """
    
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    event_type = cloud_event['type']
    
    print(f'Processing file: {file_name} from bucket: {bucket_name}')
    print(f'Event type: {event_type}')
    
    # Read file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    file_metadata = {
        'file_name': file_name,
        'bucket_name': bucket_name,
        'size': blob.size,
        'content_type': blob.content_type,
        'created': blob.time_created,
        'updated': blob.updated,
        'event_type': event_type,
        'processed_at': datetime.utcnow()
    }
    
    # Read file content (for text files)
    try:
        if blob.content_type and 'text' in blob.content_type:
            content = blob.download_as_text()
            file_metadata['content_preview'] = content[:500]
            file_metadata['line_count'] = len(content.split('\n'))
        else:
            file_metadata['content_preview'] = 'Binary file'
    except Exception as e:
        print(f'Error reading file content: {e}')
        file_metadata['content_preview'] = 'Error reading content'
    
    # Write to Firestore
    doc_ref = firestore_client.collection('processed_files').document()
    doc_ref.set(file_metadata)
    print(f'Written to Firestore with document ID: {doc_ref.id}')
    
    # Prepare message for Pub/Sub
    message_data = {
        'firestore_doc_id': doc_ref.id,
        'file_name': file_name,
        'bucket_name': bucket_name,
        'event_type': event_type,
        'timestamp': datetime.utcnow().isoformat()
    }
    
    # Publish to Pub/Sub
    message_json = json.dumps(message_data)
    message_bytes = message_json.encode('utf-8')
    
    future = publisher.publish(PUBSUB_TOPIC, message_bytes)
    message_id = future.result()
    print(f'Published message to Pub/Sub with ID: {message_id}')
    
    return {'status': 'success', 'firestore_doc_id': doc_ref.id, 'pubsub_message_id': message_id}


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered Cloud Function for manual file processing.
    Expects JSON with bucket_name and file_name.
    
    Service Account Permissions Required:
    - roles/storage.admin (Storage Admin)
    - roles/datastore.user (Datastore User)
    - roles/pubsub.publisher (Pub/Sub Publisher)
    """
    
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket_name' not in request_json or 'file_name' not in request_json:
        return {'error': 'Missing bucket_name or file_name in request'}, 400
    
    bucket_name = request_json['bucket_name']
    file_name = request_json['file_name']
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': f'File {file_name} not found in bucket {bucket_name}'}, 404
        
        file_metadata = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'size': blob.size,
            'content_type': blob.content_type,
            'created': blob.time_created,
            'updated': blob.updated,
            'processed_at': datetime.utcnow(),
            'processing_type': 'manual_http'
        }
        
        # Read file content
        try:
            if blob.content_type and 'text' in blob.content_type:
                content = blob.download_as_text()
                file_metadata['content_preview'] = content[:500]
                file_metadata['line_count'] = len(content.split('\n'))
            else:
                content = blob.download_as_bytes()
                file_metadata['content_preview'] = 'Binary file'
                file_metadata['file_size_bytes'] = len(content)
        except Exception as e:
            print(f'Error reading file content: {e}')
            file_metadata['content_preview'] = 'Error reading content'
        
        # Write to Firestore
        doc_ref = firestore_client.collection('processed_files').document()
        doc_ref.set(file_metadata)
        print(f'Written to Firestore with document ID: {doc_ref.id}')
        
        # Publish to Pub/Sub
        message_data = {
            'firestore_doc_id': doc_ref.id,
            'file_name': file_name,
            'bucket_name': bucket_name,
            'processing_type': 'manual_http',
            'timestamp': datetime.utcnow().isoformat()
        }
        
        message_json = json.dumps(message_data)
        message_bytes = message_json.encode('utf-8')
        
        future = publisher.publish(PUBSUB_TOPIC, message_bytes)
        message_id = future.result()
        print(f'Published message to Pub/Sub with ID: {message_id}')
        
        return {
            'status': 'success',
            'firestore_doc_id': doc_ref.id,
            'pubsub_message_id': message_id,
            'file_metadata': {
                'file_name': file_name,
                'size': blob.size,
                'content_type': blob.content_type
            }
        }, 200
        
    except Exception as e:
        print(f'Error processing file: {e}')
        return {'error': str(e)}, 500


@functions_framework.cloud_event
def process_pubsub_message(cloud_event):
    """
    Pub/Sub-triggered Cloud Function for processing messages.
    Demonstrates reading from Pub/Sub and updating Firestore.
    
    Service Account Permissions Required:
    - roles/datastore.user (Datastore User)
    """
    
    pubsub_message = base64.b64decode(cloud_event.data['message']['data']).decode('utf-8')
    message_data = json.loads(pubsub_message)
    
    print(f'Received Pub/Sub message: {message_data}')
    
    # Update Firestore document if firestore_doc_id is present
    if 'firestore_doc_id' in message_data:
        doc_ref = firestore_client.collection('processed_files').document(message_data['firestore_doc_id'])
        doc_ref.update({
            'pubsub_processed': True,
            'pubsub_processed_at': datetime.utcnow()
        })
        print(f'Updated Firestore document: {message_data["firestore_doc_id"]}')
    
    # Log message processing
    log_ref = firestore_client.collection('pubsub_logs').document()
    log_ref.set({
        'message_data': message_data,
        'processed_at': datetime.utcnow()
    })
    
    return {'status': 'success'}


def batch_process_bucket(bucket_name, prefix=''):
    """
    Utility function to batch process all files in a bucket.
    Can be called from another function or script.
    
    Service Account Permissions Required:
    - roles/storage.admin (Storage Admin)
    - roles/datastore.user (Datastore User)
    - roles/pubsub.publisher (Pub/Sub Publisher)
    """
    
    bucket = storage_client.bucket(bucket_name)
    blobs = bucket.list_blobs(prefix=prefix)
    
    processed_count = 0
    
    for blob in blobs:
        try:
            file_metadata = {
                'file_name': blob.name,
                'bucket_name': bucket_name,
                'size': blob.size,
                'content_type': blob.content_type,
                'created': blob.time_created,
                'updated': blob.updated,
                'processed_at': datetime.utcnow(),
                'processing_type': 'batch'
            }
            
            doc_ref = firestore_client.collection('processed_files').document()
            doc_ref.set(file_metadata)
            
            message_data = {
                'firestore_doc_id': doc_ref.id,
                'file_name': blob.name,
                'bucket_name': bucket_name,
                'processing_type': 'batch',
                'timestamp': datetime.utcnow().isoformat()
            }
            
            message_json = json.dumps(message_data)
            message_bytes = message_json.encode('utf-8')
            
            publisher.publish(PUBSUB_TOPIC, message_bytes)
            
            processed_count += 1
            print(f'Processed file: {blob.name}')
            
        except Exception as e:
            print(f'Error processing {blob.name}: {e}')
    
    return {'processed_count': processed_count}